import { execution } from '@dynatrace-sdk/automation-utils';
import { entitiesClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    const tagsObj = typeof input.tagsJson === 'string' ? JSON.parse(input.tagsJson) : input.tagsJson;
    const action = (input.tagAction || 'ADD').toUpperCase();

    let tags = [];
    if (action === 'REMOVE') {
      tags = Object.keys(tagsObj).map(key => ({ key }));
    } else {
      tags = Object.entries(tagsObj).map(([key, value]) => ({ key, value: String(value) }));
    }

    await entitiesClient.updateEntityTags({
      id: input.entityId,
      body: {
        tags: tags
      }
    });

    console.log(`Tags ${action}ed on entity ${input.entityId}`);

    return {
      entityId: input.entityId,
      action: action,
      tagCount: tags.length,
      success: true,
      message: `Tags ${action}ed successfully`
    };
  } catch (error) {
    console.error('Error applying tags:', error);
    throw new Error(`Failed to apply tags: ${error}`);
  }
}
